class Program
{
    static int BinarySearch(int[] nums, int target)
    {
        int left = 0, right = nums.Length - 1;
        while (left <= right)
        {
            int mid = left + (right - left) / 2;
            if (nums[mid] == target) return mid;
            else if (nums[mid] < target) left = mid + 1;
            else right = mid - 1;
        }
        return -1;
    }

    static int LeftmostInsert(int[] nums, int target)
    {
        int left = 0, right = nums.Length;
        while (left < right)
        {
            int mid = left + (right - left) / 2;
            if (nums[mid] < target) left = mid + 1;
            else right = mid;
        }
        return left;
    }

    static void Main()
    {
        int[] nums = { 1, 3, 5, 7, 9, 11 };
        Console.WriteLine(BinarySearch(nums, 7));      // 3
        Console.WriteLine(BinarySearch(nums, 6));      // -1
        Console.WriteLine(LeftmostInsert(nums, 5));    // 2
        Console.WriteLine(LeftmostInsert(nums, 6));    // 3
    }
}

