class Program
{
    static bool IsPalindrome(string s)
    {
        int left = 0, right = s.Length - 1;
        while (left < right)
        {
            if (s[left] != s[right]) return false;
            left++;
            right--;
        }
        return true;
    }

    static int[] TwoSumSorted(int[] nums, int target)
    {
        int left = 0, right = nums.Length - 1;
        while (left < right)
        {
            int sum = nums[left] + nums[right];
            if (sum == target) return new int[] { left, right };
            else if (sum < target) left++;
            else right--;
        }
        return new int[] {};
    }

    static void Main()
    {
        Console.WriteLine(IsPalindrome("racecar"));   // True
        Console.WriteLine(IsPalindrome("hello"));     // False

        int[] result = TwoSumSorted(new int[] { 1, 3, 5, 7, 9 }, 8);
        Console.WriteLine($"{result[0]},{result[1]}");  // 0,3
    }
}

