class Program
{
    static int SubarraySum(int[] nums, int k)
    {
        var prefixCount = new Dictionary<int, int>();
        prefixCount[0] = 1;
        int sum = 0, count = 0;
        foreach (int n in nums)
        {
            sum += n;
            if (prefixCount.ContainsKey(sum - k))
                count += prefixCount[sum - k];
            prefixCount[sum] = prefixCount.GetValueOrDefault(sum) + 1;
        }
        return count;
    }

    static void Main()
    {
        int[] nums = { 2, 4, 1, 3, 5 };
        int[] prefix = new int[nums.Length + 1];
        for (int i = 0; i < nums.Length; i++)
            prefix[i + 1] = prefix[i] + nums[i];

        Console.WriteLine(prefix[4] - prefix[1]);  // sum(1..3) = 4+1+3 = 8
        Console.WriteLine(SubarraySum(new int[] { 1, 1, 1 }, 2));  // 2
    }
}

